mapper.update:
UPDATE board
SET board_view_count = board_view_count + 1
WHERE board_idx = #{boardIdx}

UPDATE reply
SET reply_step = reply_step + 1
WHERE board_idx = #{boardIdx}
  AND reply_ref  = #{ref}
  AND reply_step > #{step}

UPDATE reply
SET reply_ref = #{replyRef}
WHERE reply_idx = #{replyIdx}

mapper.select:
SELECT COUNT(*)
FROM member
WHERE mem_Id = #{memId}

SELECT COUNT(*)
FROM member
WHERE mem_Id = #{memId}
  AND mem_Pwd = #{memPwd}
